Describe 'Get-SemanticVersion' {
    Context 'from a VERSION file' {
        It 'parses a valid semver string' {
            $tmpFile = Join-Path $TestDrive 'VERSION'
            Set-Content -Path $tmpFile -Value '1.2.3'
